 * public int rand7();
 * @return a random integer in the range1 to7
 */
class Solution extends SolBase {
    public int rand10() {
        int index = 0;
        while (true) {
            int row = rand7();
            int col = rand7();
            index = (row - 1) * 7 + col;
            if (index <= 40) {
                return (index - 1) % 10 + 1;
            }
        }
    }
}
